# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import websockets
import json
import uuid
from typing import Dict, Set, List
from dataclasses import dataclass, asdict
from datetime import datetime

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int
    owner_id: str
    created_at: datetime

@dataclass
class Player:
    id: str
    username: str
    inventory: Dict[str, int]
    websocket: object

class InventorySystem:
    def __init__(self):
        self.items: Dict[str, Item] = {}
        self.players: Dict[str, Player] = {}
        self.trades: Dict[str, Dict] = {}
        self.lock = asyncio.Lock()

    async def create_player(self, player_id: str, username: str, websocket):
        async with self.lock:
            self.players[player_id] = Player(
                id=player_id,
                username=username,
                inventory={},
                websocket=websocket
            )
            await self.send_update(player_id, {"type": "player_created", "username": username})

    async def add_item(self, item_id: str, name: str, item_type: str, value: int, owner_id: str):
        async with self.lock:
            item = Item(
                id=item_id,
                name=name,
                type=item_type,
                value=value,
                owner_id=owner_id,
                created_at=datetime.now()
            )
            self.items[item_id] = item
            if owner_id in self.players:
                self.players[owner_id].inventory[item_id] = self.players[owner_id].inventory.get(item_id, 0) + 1
            await self.broadcast_item_update(item_id, "created")

    async def transfer_item(self, item_id: str, from_player_id: str, to_player_id: str):
        async with self.lock:
            if item_id not in self.items:
                return False
                
            item = self.items[item_id]
            if item.owner_id != from_player_id:
                return False
                
            # Update item ownership
            item.owner_id = to_player_id
            item.updated_at = datetime.now()
            
            # Update inventories
            if from_player_id in self.players:
                if item_id in self.players[from_player_id].inventory:
                    self.players[from_player_id].inventory[item_id] -= 1
                    if self.players[from_player_id].inventory[item_id] <= 0:
                        del self.players[from_player_id].inventory[item_id]
            
            if to_player_id in self.players:
                self.players[to_player_id].inventory[item_id] = self.players[to_player_id].inventory.get(item_id, 0) + 1
            
            # Send updates to both players
            await self.send_update(from_player_id, {
                "type": "item_transferred",
                "item_id": item_id,
                "from": from_player_id,
                "to": to_player_id,
                "status": "success"
            })
            
            await self.send_update(to_player_id, {
                "type": "item_received",
                "item_id": item_id,
                "from": from_player_id,
                "status": "success"
            })
            
            await self.broadcast_item_update(item_id, "transferred")
            return True

    async def start_trade(self, player1_id: str, player2_id: str, items_to_trade: Dict[str, List[str]]):
        async with self.lock:
            trade_id = str(uuid.uuid4())
            self.trades[trade_id] = {
                "id": trade_id,
                "players": [player1_id, player2_id],
                "items": items_to_trade,
                "status": "pending"
            }
            
            await self.send_update(player1_id, {
                "type": "trade_started",
                "trade_id": trade_id,
                "player": player2_id,
                "items": items_to_trade
            })
            
            await self.send_update(player2_id, {
                "type": "trade_received",
                "trade_id": trade_id,
                "player": player1_id,
                "items": items_to_trade
            })
            
            return trade_id

    async def accept_trade(self, trade_id: str, player_id: str):
        async with self.lock:
            if trade_id not in self.trades:
                return False
                
            trade = self.trades[trade_id]
            if player_id not in trade["players"]:
                return False
                
            # Check if both players have accepted
            trade["status"] = "accepted"
            
            # Perform the actual trade
            player1_id, player2_id = trade["players"]
            items_to_trade = trade["items"]
            
            # Transfer items from player1 to player2
            success = True
            for item_id in items_to_trade.get(player1_id, []):
                if not await self.transfer_item(item_id, player1_id, player2_id):
                    success = False
                    break
            
            # Transfer items from player2 to player1
            if success:
                for item_id in items_to_trade.get(player2_id, []):
                    if not await self.transfer_item(item_id, player2_id, player1_id):
                        success = False
                        break
            
            if success:
                trade["status"] = "completed"
                await self.send_update(player1_id, {
                    "type": "trade_completed",
                    "trade_id": trade_id,
                    "status": "success"
                })
                await self.send_update(player2_id, {
                    "type": "trade_completed",
                    "trade_id": trade_id,
                    "status": "success"
                })
            else:
                trade["status"] = "failed"
                await self.send_update(player1_id, {
                    "type": "trade_failed",
                    "trade_id": trade_id,
                    "status": "failed"
                })
                await self.send_update(player2_id, {
                    "type": "trade_failed",
                    "trade_id": trade_id,
                    "status": "failed"
                })
            
            # Remove completed trade
            if trade["status"] in ["completed", "failed"]:
                del self.trades[trade_id]
            
            return success

    async def get_player_inventory(self, player_id: str):
        async with self.lock:
            if player_id not in self.players:
                return {}
            return self.players[player_id].inventory

    async def send_update(self, player_id: str, message: Dict):
        if player_id in self.players:
            try:
                await self.players[player_id].websocket.send(json.dumps(message))
            except:
                pass

    async def broadcast_item_update(self, item_id: str, action: str):
        item = self.items.get(item_id)
        if not item:
            return
            
        message = {
            "type": "item_update",
            "item_id": item_id,
            "action": action,
            "owner_id": item.owner_id
        }
        
        # Send to owner if they're online
        if item.owner_id in self.players:
            await self.send_update(item.owner_id, message)

class MMOGameServer:
    def __init__(self):
        self.inventory_system = InventorySystem()
        self.active_connections: Set[object] = set()

    async def handle_client(self, websocket, path):
        self.active_connections.add(websocket)
        player_id = None
        
        try:
            async for message in websocket:
                data = json.loads(message)
                
                if data.get("type") == "login":
                    player_id = data.get("player_id")
                    username = data.get("username")
                    await self.inventory_system.create_player(player_id, username, websocket)
                    
                elif data.get("type") == "create_item":
                    item_id = str(uuid.uuid4())
                    await self.inventory_system.add_item(
                        item_id=item_id,
                        name=data.get("name"),
                        item_type=data.get("type"),
                        value=data.get("value"),
                        owner_id=player_id
                    )
                    
                elif data.get("type") == "transfer_item":
                    await self.inventory_system.transfer_item(
                        item_id=data.get("item_id"),
                        from_player_id=player_id,
                        to_player_id=data.get("to_player_id")
                    )
                    
                elif data.get("type") == "start_trade":
                    trade_id = await self.inventory_system.start_trade(
                        player1_id=player_id,
                        player2_id=data.get("player2_id"),
                        items_to_trade=data.get("items_to_trade")
                    )
                    
                elif data.get("type") == "accept_trade":
                    await self.inventory_system.accept_trade(
                        trade_id=data.get("trade_id"),
                        player_id=player_id
                    )
                    
                elif data.get("type") == "get_inventory":
                    inventory = await self.inventory_system.get_player_inventory(player_id)
                    await self.inventory_system.send_update(player_id, {
                        "type": "inventory_response",
                        "inventory": inventory
                    })
                    
        except Exception as e:
            pass
        finally:
            self.active_connections.discard(websocket)
            if player_id and player_id in self.inventory_system.players:
                del self.inventory_system.players[player_id]

    async def start_server(self, host="localhost", port=8765):
        server = await websockets.serve(self.handle_client, host, port)
        print(f"MMO Game Server started on {host}:{port}")
        await server.wait_closed()

# Initialize and start the server
if __name__ == "__main__":
    server = MMOGameServer()
    asyncio.run(server.start_server())